// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IHederaTokenService {
    struct TokenKey {
        uint256 keyType;
        KeyValue key;
    }

    struct KeyValue {
        bool inheritAccountKey;
        address contractId;
        bytes ed25519;
        bytes ECDSA_secp256k1;
        address delegatableContractId;
    }

    struct Expiry {
        uint32 second;
        address autoRenewAccount;
        uint32 autoRenewPeriod;
    }

    struct HederaToken {
        string name;
        string symbol;
        address treasury;
        string memo;
        bool tokenSupplyType;
        uint32 maxSupply;
        bool freezeDefault;
        TokenKey[] tokenKeys;
        Expiry expiry;
    }

    function createFungibleToken(
        HederaToken memory token,
        int64 initialTotalSupply,
        int32 decimals
    ) external payable returns (int64 responseCode, address tokenAddress);
}

contract MemeFactoryHTS {
    address constant PRECOMPILE_ADDRESS = address(0x167);

    event MemeLaunched(address indexed creator, address tokenAddress, string name, string symbol, string imageUrl);

    function createMemeToken(
        string memory name, 
        string memory symbol, 
        int64 initialSupply, 
        string memory imageUrl
    ) external returns (address) {

        IHederaTokenService.TokenKey[] memory keys = new IHederaTokenService.TokenKey[](1);

        keys[0] = IHederaTokenService.TokenKey({
            keyType: 1, // ADMIN
            key: IHederaTokenService.KeyValue({
                inheritAccountKey: false,
                contractId: address(this),
                ed25519: new bytes(0),
                ECDSA_secp256k1: new bytes(0),
                delegatableContractId: address(0)
            })
        });

        IHederaTokenService.Expiry memory expiry = IHederaTokenService.Expiry({
            second: 0,
            autoRenewAccount: address(this),
            autoRenewPeriod: 7776000 // 90 days
        });

        IHederaTokenService.HederaToken memory token = IHederaTokenService.HederaToken({
            name: name,
            symbol: symbol,
            treasury: address(this), // <--- THIS FIXES THE AUTHORIZATION ERROR
            memo: imageUrl,
            tokenSupplyType: false,
            maxSupply: 0,
            freezeDefault: false,
            tokenKeys: keys,
            expiry: expiry
        });

        // We send 40 HBAR to the precompile to ensure it has enough for the token creation fee.
        // Hedera will automatically deduct the exact fee (~10-15 HBAR) and leave the rest in the contract.
        (int64 responseCode, address tokenAddress) = IHederaTokenService(PRECOMPILE_ADDRESS).createFungibleToken{value: 40 ether}(
            token,
            initialSupply,
            8
        );

        require(responseCode == 22, "HTS Precompile Failed");

        emit MemeLaunched(msg.sender, tokenAddress, name, symbol, imageUrl);

        return tokenAddress;
    }

    receive() external payable {}
}

